using System;
using System.Collections.Generic;
using PX.Data;
using IGCM;
using IGCM.DAC;
using PX.Objects.PO;
using HeritageFabrics.PO;

namespace HeritageFabrics.IGCM
{
    public class IGCMPOLandedCostEntry_Extension : PXGraphExtension<IGCMPOLandedCostEntry>
    {
        public static bool IsActive() => true;

        [PXOverride]
        public void Persist(Action del)
        {
            // Capture container header and line PO references BEFORE base save
            IGCMPOLandedCost header = (IGCMPOLandedCost)Base.Caches[typeof(IGCMPOLandedCost)].Current;
            DateTime? containerDate = header?.ExpectedArrivalDate;

            var poRefs = new List<Tuple<string, string, int?>>();

            if (containerDate != null)
            {
                PXCache lineCache = Base.Caches[typeof(IGCMPOLandedCostLine)];
                foreach (IGCMPOLandedCostLine line in lineCache.Cached)
                {
                    PXEntryStatus status = lineCache.GetStatus(line);
                    if (status == PXEntryStatus.Deleted || status == PXEntryStatus.InsertedDeleted)
                        continue;
                    if (string.IsNullOrEmpty(line.POOrderType) || string.IsNullOrEmpty(line.PONbr))
                        continue;
                    poRefs.Add(Tuple.Create(line.POOrderType, line.PONbr, line.POLineNbr));
                }
            }

            // Execute base save
            del();

            // After successful save, propagate container date to linked PO records
            if (containerDate == null || poRefs.Count == 0) return;

            HashSet<string> updatedHeaders = new HashSet<string>();

            foreach (Tuple<string, string, int?> po in poRefs)
            {
                // Update PO Line
                if (po.Item3 != null)
                {
                    PXDatabase.Update<POLine>(
                        new PXDataFieldAssign<POLineExt.usrExpArrivalDate>(containerDate),
                        new PXDataFieldRestrict<POLine.orderType>(po.Item1),
                        new PXDataFieldRestrict<POLine.orderNbr>(po.Item2),
                        new PXDataFieldRestrict<POLine.lineNbr>(po.Item3)
                    );
                }

                // Update PO Header (once per unique PO)
                string headerKey = po.Item1 + ":" + po.Item2;
                if (!updatedHeaders.Contains(headerKey))
                {
                    PXDatabase.Update<POOrder>(
                        new PXDataFieldAssign<POOrderExt.usrExpArrivalDate>(containerDate),
                        new PXDataFieldRestrict<POOrder.orderType>(po.Item1),
                        new PXDataFieldRestrict<POOrder.orderNbr>(po.Item2)
                    );
                    updatedHeaders.Add(headerKey);
                }
            }
        }
    }
}

using System;
using PX.Data;
using PX.Data.BQL;
using PX.Objects.IN;

namespace HeritageFabrics.IN
{
    public sealed class InventoryAllocDetEnqResultExt : PXCacheExtension<InventoryAllocDetEnqResult>
    {
        public static bool IsActive() => true;

        #region UsrExpArrivalDate
        public abstract class usrExpArrivalDate : BqlDateTime.Field<usrExpArrivalDate> { }
        [PXDate]
        [PXUIField(DisplayName = "Exp. Arrival Date")]
        public DateTime? UsrExpArrivalDate { get; set; }
        #endregion
    }
}

using System;
using PX.Data;
using PX.Objects.IN;
using PX.Objects.PO;
using HeritageFabrics.PO;

namespace HeritageFabrics.IN
{
    public class InventoryAllocDetEnq_Extension : PXGraphExtension<InventoryAllocDetEnq>
    {
        public static bool IsActive() => true;

        protected void _(Events.RowSelected<InventoryAllocDetEnqResult> e)
        {
            if (e.Row == null) return;
            if (e.Row.Module != "PO" || string.IsNullOrEmpty(e.Row.RefNbr)) return;

            try
            {
                // Use PXCache-based value access instead of GetExtension
                // to avoid extension initialization failures on inquiry result DACs
                DateTime? existing = (DateTime?)e.Cache.GetValue(e.Row, "UsrExpArrivalDate");
                if (existing != null) return;

                // Look up POOrder to get UsrExpArrivalDate
                POOrder po = null;

                if (!string.IsNullOrEmpty(e.Row.QADocType))
                {
                    po = PXSelectReadonly<POOrder,
                        Where<POOrder.orderType, Equal<Required<POOrder.orderType>>,
                        And<POOrder.orderNbr, Equal<Required<POOrder.orderNbr>>>>>
                        .Select(Base, e.Row.QADocType, e.Row.RefNbr);
                }

                // Fallback: lookup by order number only
                if (po == null)
                {
                    po = PXSelectReadonly<POOrder,
                        Where<POOrder.orderNbr, Equal<Required<POOrder.orderNbr>>>>
                        .Select(Base, e.Row.RefNbr);
                }

                if (po != null)
                {
                    // Use static PXCache<T>.GetExtension — safer than instance method
                    // for records loaded via PXSelectReadonly in foreign graphs
                    POOrderExt poExt = PXCache<POOrder>.GetExtension<POOrderExt>(po);
                    if (poExt?.UsrExpArrivalDate != null)
                    {
                        e.Cache.SetValue(e.Row, "UsrExpArrivalDate", poExt.UsrExpArrivalDate);
                    }
                }
            }
            catch
            {
                // Silently handle extension retrieval failures
                // to prevent breaking the Inventory Allocation screen
            }
        }
    }
}

Sql.CDATA:
IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID('POOrder') AND name = 'UsrExpArrivalDate')
    ALTER TABLE POOrder ADD UsrExpArrivalDate datetime NULL;

IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID('POOrder') AND name = 'UsrActArrivalDate')
    ALTER TABLE POOrder ADD UsrActArrivalDate datetime NULL;

IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID('POLine') AND name = 'UsrExpArrivalDate')
    ALTER TABLE POLine ADD UsrExpArrivalDate datetime NULL;

IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID('POLine') AND name = 'UsrActArrivalDate')
    ALTER TABLE POLine ADD UsrActArrivalDate datetime NULL;

IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID('SOOrder') AND name = 'UsrHubSpotDealId')
    ALTER TABLE SOOrder ADD UsrHubSpotDealId nvarchar(50) NULL;

IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID('BAccount') AND name = 'UsrDisablePayLink')
    ALTER TABLE BAccount ADD UsrDisablePayLink bit NULL;

IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID('POOrder') AND name = 'UsrContainerRef')
    ALTER TABLE POOrder ADD UsrContainerRef nvarchar(50) NULL;

IF NOT EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID('SOOrder') AND name = 'UsrWMSStatus')
    ALTER TABLE SOOrder ADD UsrWMSStatus nvarchar(20) NULL;
